torch::Tensor max_reduction_cuda(torch::Tensor input, int reduction_dim) {
    auto sizes = input.sizes();
    int batch_size = sizes[0];
    int dim1 = sizes[1];
    int dim2 = sizes[2];

    auto strides = input.strides();
    int stride0 = strides[0];
    int stride1 = strides[1];
    int stride2 = strides[2];

    torch::Tensor output;
    if (reduction_dim == 1) {
        output = torch::empty({batch_size, dim2}, input.options());
    } else if (reduction_dim == 2) {
        output = torch::empty({batch_size, dim1}, input.options());
    } else {
        throw std::runtime_error("Only reduction over dimension 1 or 2 is supported");
    }

    // Optimized block size - multiple of 32 for warp efficiency
    const int block_size = 256;
    dim3 grid_dims;

    if (reduction_dim == 1) {
        grid_dims = dim3(batch_size, dim2);
    } else {
        grid_dims = dim3(batch_size, dim1);
    }

    // Launch kernel with optimized configuration
    AT_DISPATCH_FLOATING_TYPES(input.scalar_type(), "max_reduction_cuda", ([&] {
        if (reduction_dim == 1) {
            max_reduction_dim1_kernel<scalar_t><<<grid_dims, block_size>>>(
                input.data_ptr<scalar_t>(),
                output.data_ptr<scalar_t>(),
                batch_size,
                dim1,
                dim2,
                stride0,
                stride1,
                stride2
            );
        } else {
            max_reduction_dim2_kernel<scalar_t><<<grid_dims, block_size>>>(
                input.data_ptr<scalar_t>(),
                output.data_ptr<scalar_t>(),
                batch_size,
                dim1,
                dim2,
                stride0,
                stride1,
                stride2
            );
        }
    }));

    return output;
}
