# Compile the inline CUDA code with optimization flags
max_reduction_module = load_inline(
    name="max_reduction",
    cpp_sources=max_reduction_cpp_source,
    cuda_sources=max_reduction_source,
    functions=["max_reduction_cuda"],
    verbose=False,
    extra_cflags=["-O3", "-DNDEBUG"],
    extra_ldflags=["-lcudart"],
    extra_include_paths=["/usr/local/cuda/include"],
)

class ModelNew(nn.Module):
    """
    Optimized model that performs Max reduction over a specific dimension using custom CUDA kernel.
    """
    def __init__(self, dim: int):
        """
        Initializes the model with the dimension to reduce over.

        Args:
            dim (int): The dimension to reduce over (1 or 2).
        """
        super(ModelNew, self).__init__()
        self.dim = dim
        self.max_reduction = max_reduction_module

    def forward(self, x: torch.Tensor) -> torch.Tensor:
        """
        Applies Max reduction over the specified dimension using custom CUDA kernel.

        Args:
            x (torch.Tensor): Input tensor of shape (batch_size, dim1, dim2).

        Returns:
            torch.Tensor: Output tensor after Max reduction over the specified dimension.
        """
        if x.is_cuda:
            return self.max_reduction.max_reduction_cuda(x, self.dim)
        else:
            return torch.max(x, dim=self.dim)[0]

